import json, sys
data = json.load(sys.stdin)
# Get unique project files and their IDs, skip restore-only entries
projects = {}
for pid, info in data.items():
    pf = info['projectFile']
    targets = [t['targetName'] for t in info['entryTargets'].values()]
    if pf not in projects:
        projects[pf] = {'ids': [], 'targets': set()}
    projects[pf]['ids'].append(int(pid))
    projects[pf]['targets'].update(targets)

for pf, info in sorted(projects.items()):
    print(f'{pf}')
    print(f'  IDs: {sorted(info[\"ids\"])}')
    print(f'  Entry targets: {sorted(info[\"targets\"])}')
    print()
"
","description":"Parse project list from binlog","initial_wait":10}

